class AgeValidator {
    private static final int MINIMUM_LEGAL_DRINKING_AGE = 21;
    private static final int MAXIMUM_ENROLLMENT_AGE = 65;

    boolean isEligibleForProgram(int age) {
        return age >= MINIMUM_LEGAL_DRINKING_AGE && age <= MAXIMUM_ENROLLMENT_AGE;
    }

    boolean isValidAge(int age) {
        return age > 0 && age < 150;
    }
}
